import { forwardRef, useContext, useId } from 'react';
import { RadioGroupContext } from '../RadioGroup/RadioGroup';
import { useControllableState } from '../../hooks/useControllableState';

export interface ArvoRadioProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'> {
  value: string;
  name?: string;
  label?: string | null;
  isChecked?: boolean;
  defaultChecked?: boolean;
  isDisabled?: boolean;
  isRequired?: boolean;
  isReadOnly?: boolean;
  isInvalid?: boolean;
  isLoading?: boolean;
  size?: 'sm' | 'lg';
  errorMsg?: string | null;
  onChange?: (detail: { value: string; name: string }) => void;
  onFocus?: React.FocusEventHandler<HTMLInputElement>;
  onBlur?: React.FocusEventHandler<HTMLInputElement>;
}

const ArvoRadio = forwardRef<HTMLDivElement, ArvoRadioProps>(
  function ArvoRadio(
    {
      value,
      name,
      label = null,
      isChecked: checkedProp,
      defaultChecked = false,
      isDisabled = false,
      isRequired = false,
      isReadOnly = false,
      isInvalid = false,
      isLoading = false,
      size = 'lg',
      errorMsg = null,
      onChange,
      onFocus,
      onBlur,
      className,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const inputId = `arvo-radio-${uid}`;
    const errorId = `arvo-radio-err-${uid}`;

    const [ownChecked, setOwnChecked] = useControllableState(checkedProp, defaultChecked);

    const group = useContext(RadioGroupContext);
    const resolvedName = name ?? group?.name ?? '';
    const resolvedSize = group ? group.size : size;
    const resolvedDisabled = isDisabled || (group ? group.isDisabled : false);
    const resolvedReadonly = isReadOnly || (group ? group.isReadOnly : false);
    const resolvedLoading = isLoading || (group ? group.isLoading : false);
    const resolvedChecked = group ? group.selectedValue === value : ownChecked;

    const classes = [
      'arvo-radio',
      `arvo-radio--${resolvedSize}`,
      resolvedLoading && 'loading',
      resolvedDisabled && 'is-disabled',
      resolvedReadonly && 'is-readonly',
      isInvalid && 'has-error',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    function handleChange() {
      if (resolvedDisabled || resolvedLoading || resolvedReadonly) return;
      if (group) {
        group.onChildChange(value);
      } else {
        setOwnChecked(true);
      }
      onChange?.({ value, name: resolvedName });
    }

    return (
      <div ref={ref} className={classes} aria-busy={resolvedLoading || undefined} {...rest}>
        <label className="arvo-radio__field" htmlFor={inputId}>
          <input
            id={inputId}
            className="arvo-radio__input"
            type="radio"
            name={resolvedName}
            value={value}
            checked={resolvedChecked}
            disabled={resolvedDisabled}
            readOnly={resolvedReadonly}
            required={isRequired}
            aria-invalid={isInvalid || undefined}
            aria-required={isRequired || undefined}
            aria-describedby={isInvalid && errorMsg ? errorId : undefined}
            tabIndex={resolvedReadonly ? -1 : 0}
            onChange={handleChange}
            onFocus={onFocus}
            onBlur={onBlur}
          />
          <span className="arvo-radio__control" aria-hidden="true" />
          {label && <span className="arvo-radio__text">{label}</span>}
        </label>
        {isInvalid && errorMsg && (
          <div
            className="arvo-inline-alert arvo-inline-alert--error"
            id={errorId}
            role="alert"
          >
            <span className="arvo-inline-alert__ico" aria-hidden="true" />
            <span className="arvo-inline-alert__msg">{errorMsg}</span>
          </div>
        )}
      </div>
    );
  }
);

export default ArvoRadio;
